"use strict";parserFactory.register("novelplex.org",()=>new NovelplexParser);class NovelplexParser extends Parser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll(".nAP__TOCArea a")].map(e=>this.hyperLinkToChapter(e))}hyperLinkToChapter(e){return{sourceUrl:e.href,title:e.querySelector("p").textContent}}findContent(e){return e.querySelector(".halChap--kontenInner")}extractTitleImpl(e){return e.querySelector(".headerNovel__wrap h2")}removeUnwantedElementsFromContentElement(e){util.removeChildElementsMatchingSelector(e,".pt_aBody, .pt_aButton"),super.removeUnwantedElementsFromContentElement(e)}findChapterTitle(e){return e.querySelector(".halChap h1")}findCoverImageUrl(e){return util.getFirstImgSrc(e,".headerNovel")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll(".summary_mobile")]}}